<script setup lang="ts">import { useQuery, useQueryClient } from '@tanstack/vue-query'; import { AlertCircle, ArrowRight, CheckCircle2, Download, Library, PlayCircle, RefreshCw, Sparkles, Tv } from '@lucide/vue'; import { api } from '../api/client'; import type { Dashboard } from '../api/types'; import PageHeader from '../components/PageHeader.vue'; import StateBlock from '../components/StateBlock.vue'; import { useUIStore } from '../stores/ui'; const ui=useUIStore(),queryClient=useQueryClient(); const query=useQuery({queryKey:['dashboard'],queryFn:()=>api<Dashboard>('/dashboard')}); async function sync(){try{await api('/tasks/sync',{method:'POST'});ui.toast('同步任务已经启动');queryClient.invalidateQueries({queryKey:['dashboard']})}catch(e){ui.toast(e instanceof Error?e.message:'同步失败','error')}}</script>
<template><div class="page-grid"><PageHeader eyebrow="Today" title="今天也在安心追番" description="更新、下载和媒体库状态已经汇总到这里。"><button class="btn btn-primary" @click="sync"><RefreshCw :size="17"/>立即同步</button></PageHeader><StateBlock v-if="query.isLoading.value" state="loading"/><StateBlock v-else-if="query.isError.value" state="error" title="概览加载失败" @retry="query.refetch()"/><template v-else-if="query.data.value"><section class="grid gap-4 sm:grid-cols-2 xl:grid-cols-5"><article v-for="item in [{label:'活跃订阅',value:query.data.value.active_subscriptions,icon:Tv,tone:'brand'},{label:'下载记录',value:query.data.value.downloads,icon:Download,tone:'sky'},{label:'番剧图鉴',value:query.data.value.library_items,icon:Library,tone:'brand'},{label:'本地剧集',value:query.data.value.local_series,icon:PlayCircle,tone:'sky'},{label:'待处理问题',value:query.data.value.open_issues,icon:AlertCircle,tone:'danger'}]" :key="item.label" class="panel p-5"><component :is="item.icon" :size="20" :class="item.tone==='danger'?'text-[var(--danger)]':item.tone==='sky'?'text-[var(--sky)]':'text-[var(--brand)]'"/><p class="muted mt-5 text-xs font-extrabold uppercase tracking-wider">{{ item.label }}</p><strong class="mt-1 block text-3xl font-black">{{ item.value }}</strong></article></section><section class="grid gap-5 xl:grid-cols-[1.4fr_.8fr]"><div class="panel p-5 sm:p-6"><div class="mb-5 flex items-center justify-between"><div><p class="eyebrow">AUTOMATION</p><h3 class="mt-1 text-xl font-black">自动化任务</h3></div><RouterLink to="/health" class="btn btn-quiet">查看健康状态<ArrowRight :size="16"/></RouterLink></div><div class="grid gap-3 sm:grid-cols-2"><article v-for="task in query.data.value.tasks" :key="task.title" class="panel-muted p-4"><div class="flex items-start justify-between gap-3"><span class="grid h-9 w-9 place-items-center rounded-xl" :class="task.status_tone==='rose'?'bg-red-100 text-red-700':task.status_tone==='amber'?'bg-amber-100 text-amber-700':'bg-emerald-100 text-emerald-700'"><AlertCircle v-if="task.status_tone==='rose'" :size="18"/><CheckCircle2 v-else :size="18"/></span><span class="badge">{{ task.status_label }}</span></div><h4 class="mt-4 font-extrabold">{{ task.title }}</h4><p class="muted mt-1 text-sm leading-5">{{ task.summary }}</p><p v-if="task.progress_text" class="mt-2 text-xs font-bold text-[var(--sky)]">{{ task.progress_text }}</p></article></div></div><aside class="panel p-5 sm:p-6"><div class="flex items-center gap-3"><span class="grid h-10 w-10 place-items-center rounded-xl bg-[var(--brand-soft)] text-[var(--brand)]"><Sparkles :size="19"/></span><div><p class="eyebrow">RECENT</p><h3 class="text-xl font-black">最近下载</h3></div></div><div v-if="query.data.value.recent_downloads.length" class="mt-5 divide-y divide-[var(--line)]"><div v-for="item in query.data.value.recent_downloads" :key="item.ID" class="py-3"><p class="line-clamp-2 text-sm font-bold">{{ item.Title }}</p><p class="muted mt-1 text-xs">{{ item.Episode || '集数待识别' }} · {{ item.Status }}</p></div></div><div v-else class="muted mt-10 text-center text-sm">还没有下载记录</div></aside></section></template></div></template>
